INSERT INTO t_p5815085_family_assistant_pro.faith_name_days (name, saint_name, day, month, religion, description) VALUES
-- Мужские имена
('Антон', 'Преподобный Антоний Великий', 30, 1, 'orthodox', 'Основатель монашества, египетский подвижник IV века. Провёл десятилетия в пустыне в молитве и посте.'),
('Аркадий', 'Преподобный Аркадий Новоторжский', 26, 2, 'orthodox', 'Подвижник XI века, ученик Ефрема Новоторжского. Основатель монашеской жизни в Торжке.'),
('Вячеслав', 'Благоверный князь Вячеслав Чешский', 11, 3, 'orthodox', 'Чешский князь X века, мученик за веру. Убит братом за приверженность христианству. Покровитель Чехии.'),
('Григорий', 'Святитель Григорий Богослов', 7, 2, 'orthodox', 'Архиепископ Константинопольский, один из трёх Вселенских учителей. Великий богослов и поэт IV века.'),
('Егор', 'Великомученик Георгий Победоносец', 6, 5, 'orthodox', 'Народная форма имени Георгий. Воин-мученик, символ победы над злом. Покровитель воинов и земледельцев.'),
('Захар', 'Праведный Захария, отец Иоанна Предтечи', 18, 9, 'orthodox', 'Ветхозаветный священник, отец Иоанна Крестителя. Пророк, прославляемый Церковью как праведник.'),
('Лука', 'Апостол и евангелист Лука', 31, 10, 'orthodox', 'Один из четырёх евангелистов, спутник апостола Павла. Врач по профессии, написал Евангелие и Деяния апостолов.'),
('Марк', 'Апостол и евангелист Марк', 8, 5, 'orthodox', 'Один из четырёх евангелистов, ученик апостола Петра. Основатель Александрийской Церкви.'),
('Степан', 'Первомученик архидиакон Стефан', 9, 1, 'orthodox', 'Первый христианский мученик, один из семи первых диаконов. Был побит камнями за проповедь Христа.'),
('Фёдор', 'Великомученик Феодор Тирон', 2, 3, 'orthodox', 'Воин-мученик IV века. Отказался принести жертву языческим богам и был сожжён. Покровитель воинов.'),
('Эдуард', 'Благоверный король Эдуард Исповедник', 26, 10, 'orthodox', 'Английский король XI века, канонизированный за благочестие и заботу о бедных. Почитается в православии.'),
-- Женские имена
('Василиса', 'Мученица Василисса Никомидийская', 3, 9, 'orthodox', 'Юная мученица III века. Приняла смерть за отказ отречься от Христа. Образец стойкости в вере.'),
('Вероника', 'Праведная Вероника Иерусалимская', 25, 7, 'orthodox', 'Благочестивая женщина, отёрла лицо Христа на пути к Голгофе. На плате запечатлелся Его лик.'),
('Виктория', 'Мученица Виктория Кордубская', 17, 11, 'orthodox', 'Испанская мученица III века, пострадавшая за веру при императоре Диоклетиане.'),
('Диана', 'Мученица Диана (Иулиания) Птолемаидская', 17, 3, 'orthodox', 'Раннехристианская мученица, пострадавшая в Птолемаиде. В православии имя нередко связывается с Иулианией.'),
('Зинаида', 'Мученица Зинаида Тарсийская', 11, 10, 'orthodox', 'Сестра апостола Павла по некоторым преданиям. Врач, бесплатно лечившая больных во имя Христа.'),
('Инна', 'Мученик Инна Новодунский', 2, 2, 'orthodox', 'Один из первых христианских мучеников на территории Скифии (нынешняя Румыния), I–II век.'),
('Карина', 'Мученица Карина (Кира) Персидская', 28, 3, 'orthodox', 'Персидская мученица IV века, пострадавшая в годы гонений на христиан.'),
('Кира', 'Преподобная Кира Берийская', 13, 2, 'orthodox', 'Сирийская подвижница V века. Вместе с подругой Марамой провела 40 лет в затворе, питаясь лишь чечевицей.'),
('Людмила', 'Святая мученица Людмила Чешская', 29, 9, 'orthodox', 'Чешская княгиня X века, бабушка святого Вячеслава. Убита снохой за воспитание внука в христианской вере.'),
('Нина', 'Равноапостольная Нина, просветительница Грузии', 27, 1, 'orthodox', 'Просветительница Грузии IV века. Принесла христианство в Иверию, крестила царя и весь народ.'),
('Оксана', 'Мученица Ксения (Оксана) Миласская', 6, 2, 'orthodox', 'Народная украинская форма имени Ксения. День именин совпадает с памятью блаженной Ксении Петербургской.'),
('Тамара', 'Святая благоверная царица Тамара Грузинская', 14, 5, 'orthodox', 'Грузинская царица XII–XIII века, при которой Грузия достигла расцвета. Канонизирована как равноапостольная.'),
('Элина', 'Равноапостольная Елена Константинопольская', 3, 6, 'orthodox', 'Вариант имени Елена. Мать императора Константина Великого, обретшая Крест Господень в Иерусалиме.')
;